    private class ProductionTree(
        private val minLevel: Level,
        private val sanitizeSensitiveData: Boolean
    ) : Timber.DebugTree() {
        override fun isLoggable(tag: String?, priority: Int): Boolean {
            return priority >= minLevel.priority
        }

        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            if (priority < minLevel.priority) return
            val safeMessage = if (sanitizeSensitiveData) message else message
            when (priority) {
                Log.VERBOSE -> Log.v(tag ?: "AppLogger", safeMessage, t)
                Log.DEBUG -> Log.d(tag ?: "AppLogger", safeMessage, t)
                Log.INFO -> Log.i(tag ?: "AppLogger", safeMessage, t)
                Log.WARN -> Log.w(tag ?: "AppLogger", safeMessage, t)
                Log.ERROR -> Log.e(tag ?: "AppLogger", safeMessage, t)
                Log.ASSERT -> Log.wtf(tag ?: "AppLogger", safeMessage, t)
                else -> Log.d(tag ?: "AppLogger", safeMessage, t)
            }
        }
    }

    private class NoOpTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) = Unit
    }

    private class PersistentLogStore(context: Context) {
        private val prefs: SharedPreferences =
            context.getSharedPreferences("app_logger_store", Context.MODE_PRIVATE)

        fun append(level: Level, message: String) {
            try {
                val current = prefs.getString("logs", "") ?: ""
                val updated = (current + "\n" + System.currentTimeMillis() + "|" + level.name + "|" + message).takeLast(200_000)
                prefs.edit().putString("logs", updated).apply()
            } catch (_: Throwable) {
            }
        }
    }
