class LoggingExceptionHandler : Thread.UncaughtExceptionHandler {
    private val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()

    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.exception(
            throwable = throwable,
            message = "Uncaught exception on thread ${thread.name}",
            meta = mapOf("threadId" to thread.id)
        )
        defaultHandler?.uncaughtException(thread, throwable)
    }
}

class LoggingOkHttpInterceptor : okhttp3.Interceptor {
    override fun intercept(chain: okhttp3.Interceptor.Chain): okhttp3.Response {
        val request = chain.request()
        val startNs = System.nanoTime()
        val requestBodyString = request.body?.let { body ->
            try {
                val buffer = okio.Buffer()
                body.writeTo(buffer)
                buffer.readUtf8()
            } catch (t: Throwable) {
                "UNREADABLE_BODY:${t.message}"
            }
        }

        Logging.apiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = request.headers.toMultimap().mapValues { it.value.joinToString(",") },
            body = requestBodyString
        )

        return try {
            val response = chain.proceed(request)
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()
            Logging.apiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = request.headers.toMultimap().mapValues { it.value.joinToString(",") },
                body = requestBodyString,
                responseCode = response.code,
                responseHeaders = response.headers.toMultimap().mapValues { it.value.joinToString(",") },
                responseBody = responseBodyString,
                durationMs = durationMs
            )
            response
        } catch (t: Throwable) {
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            Logging.apiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = request.headers.toMultimap().mapValues { it.value.joinToString(",") },
                body = requestBodyString,
                durationMs = durationMs,
                throwable = t
            )
            throw t
        }
    }
}

interface LoggedDatabase {
    fun <T> logQuery(
        queryName: String,
        sql: String,
        parameters: Map<String, Any?> = emptyMap(),
        execute: () -> T
    ): T {
        val start = System.currentTimeMillis()
        return try {
            val result = execute()
            Logging.databaseQuery(
                queryName = queryName,
                sql = sql,
                parameters = parameters,
                durationMs = System.currentTimeMillis() - start,
                success = true
            )
            result
        } catch (t: Throwable) {
            Logging.databaseQuery(
                queryName = queryName,
                sql = sql,
                parameters = parameters,
                durationMs = System.currentTimeMillis() - start,
                success = false,
                throwable = t
            )
            throw t
        }
    }
}